from flask import Flask, request, jsonify
import jwt
import hashlib
import os
from datetime import datetime, timedelta

app = Flask(__name__)
app.config['SECRET_KEY'] = 'secret_key_here'
app.config['TOKEN_EXPIRATION'] = 3600  # 1 hour in seconds

# In-memory storage for users and tokens (replace with a database)
users = {
    "user1": hashlib.sha256("password1".encode()).hexdigest(),
    "user2": hashlib.sha256("password2".encode()).hexdigest()
}

def generate_token(user):
    payload = {
        'exp': datetime.utcnow() + timedelta(seconds=app.config['TOKEN_EXPIRATION']),
        'iat': datetime.utcnow(),
        'sub': user
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')

@app.route('/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = hashlib.sha256(request.json.get('password').encode()).hexdigest()
    if username in users and users[username] == password:
        token = generate_token(username)
        return jsonify({'token': token})
    else:
        return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({'error': 'Missing token'}), 401
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return jsonify({'message': f'Hello {payload["sub"]}!'})
    except jwt.ExpiredSignatureError:
        return jsonify({'error': 'Token has expired'}), 401
    except jwt.InvalidTokenError:
        return jsonify({'error': 'Invalid token'}), 401

